#define MM_CHECK \
   __asm__ __volatile__ ( \
		".equ TIMEOUT, 10000\n"   \
         "li x6, 0x0090000000\n" \
         "li x7, TIMEOUT\n" \
         "li x8, 4\n" \
         "LBL_RPT:\n"        \
         "li x5, 0x0\n" \
         "amoaddg.d x5, x5, 0(x6)\n" \
         "blt x5, x8, LBL_RPT\n"  \
         "beq x5, x8, LBL_ACED\n"  \
         "li  x5, 0xDEADDEAD\n" \
         "slti x0,x0,0x7ff\n" \
         "j RETURN_TO_MAIN\n" \
         "LBL_ACED:\n"        \
         "li  x5, 0xACEDACED\n" \
         "slti x0,x0,0x7fe\n" \
         "j RETURN_TO_MAIN\n" \
         VSNIP_RSV \
         );

#define VPU_TEST_START \
   __asm__ __volatile__ ( \
         "fence\n"\
         "li  x5, 0xFEEDFEED\n" \
         "slti x0,x0,0x7f2\n" \
         VSNIP_RSV \
         );

#define VPU_TEST_PASS \
   __asm__ __volatile__ ( \
         "fence\n"\
         "li x5, 0x2\n" \
         "li x6, 0x0090000000\n" \
         "amoaddg.d zero, x5, 0(x6)\n" \
         "li  x5, 0xACEDACED\n" \
         "slti x0,x0,0x7fe\n" \
         "j RETURN_TO_MAIN\n" \
         VSNIP_RSV \
         );

#define VPU_TEST_FAIL \
   __asm__ __volatile__ ( \
         "fence\n"\
         "li x5, 0x8\n" \
         "li x6, 0x0090000000\n" \
         "amoaddg.d zero, x5, 0(x6)\n" \
         "li  x5, 0xDEADDEAD\n" \
         "slti x0,x0,0x7ff\n" \
         "j RETURN_TO_MAIN\n" \
         VSNIP_RSV \
         );


